import { Component } from '@angular/core';
import { MainComponent } from './main-page/main.component';
@Component({
  standalone: true,
  selector: 'app-root',
  template: `
  <section>
    <app-main></app-main>
  </section>
  `,
  styleUrls: ['./app.component.css'],
  imports: [MainComponent]
})
export class AppComponent {
  title = 'homes';
}
